UPDATE public.projects SET description = 'A Casa do Vale explora a horizontalidade e a leveza visual através de planos brancos que parecem flutuar sobre a piscina e o deck de convívio. O contraste entre a austeridade externa e o aconchego dos ambientes internos, com forro em madeira e luz indireta, define o caráter do projeto. Com 510m², a casa foi desenhada para aproveitar a topografia e as vistas do terreno, priorizando espaços de estar generosos e uma relação constante com o exterior — piscina, deck e jardim funcionam como extensão natural da sala.' WHERE title = 'Casa do Vale';